mapper.sql:
from chat_message m
inner join chat_message_recipient r
on r.message_id = m.id
and r.recipient_user_id = #{userId}
and r.visible_status = 1
where m.conversation_id = #{conversationId}

    and m.id < #{beforeMessageId}

from chat_message m
where m.conversation_id = #{conversationId}

    and m.id < #{query.beforeMessageId}


    and m.sender_id = #{query.senderId}


    and m.message_type = #{query.messageType}


    and m.content like concat('%', #{query.keyword}, '%')

mapper.select:
select m.id, m.conversation_id as conversationId, m.sender_id as senderId, m.message_type as messageType, m.content, m.payload_json as payloadJson, m.reply_message_id as replyMessageId, m.client_message_id as clientMessageId, m.send_status as sendStatus, m.revoke_status as revokeStatus, m.revoked_by as revokedBy, m.revoked_at as revokedAt, count(r.id) as totalRecipientCount, sum(case when r.delivery_status >= 1 then 1 else 0 end) as deliveredRecipientCount, sum(case when r.delivery_status >= 2 then 1 else 0 end) as readRecipientCount, m.created_at as createdAt, m.updated_at as updatedAt from chat_message m left join chat_message_recipient r on r.message_id = m.id where m.conversation_id = #{conversationId}
and m.id < #{query.beforeMessageId}
and m.sender_id = #{query.senderId}
and m.message_type = #{query.messageType}
and m.content like concat('%', #{query.keyword}, '%')
group by m.id, m.conversation_id, m.sender_id, m.message_type, m.content, m.payload_json, m.reply_message_id, m.client_message_id, m.send_status, m.revoke_status, m.revoked_by, m.revoked_at, m.created_at, m.updated_at order by m.id desc limit #{offset}, #{size}

select m.id, m.conversation_id as conversationId, m.sender_id as senderId, m.message_type as messageType, m.content, m.payload_json as payloadJson, m.reply_message_id as replyMessageId, m.client_message_id as clientMessageId, m.send_status as sendStatus, m.revoke_status as revokeStatus, m.revoked_by as revokedBy, m.revoked_at as revokedAt, count(r.id) as totalRecipientCount, sum(case when r.delivery_status >= 1 then 1 else 0 end) as deliveredRecipientCount, sum(case when r.delivery_status >= 2 then 1 else 0 end) as readRecipientCount, m.created_at as createdAt, m.updated_at as updatedAt from chat_message m left join chat_message_recipient r on r.message_id = m.id where m.conversation_id = #{conversationId} and m.id in
#{messageId}
group by m.id, m.conversation_id, m.sender_id, m.message_type, m.content, m.payload_json, m.reply_message_id, m.client_message_id, m.send_status, m.revoke_status, m.revoked_by, m.revoked_at, m.created_at, m.updated_at
